// tsconfig.json üçün qeyd: {"experimentalDecorators": true, "emitDecoratorMetadata": true}

// 1. Sadə Parametr Dekoratoru
function logParameter(target: any, propertyKey: string, parameterIndex: number) {
  console.log(`Parameter at index ${parameterIndex} in method ${propertyKey}`);
}
class Greeter {
  greet(@logParameter name: string): string {
    return "Hello, " + name;
  }
}
const greeter = new Greeter();
console.log(greeter.greet("Alice")); // Çıxış: Parameter at index 0 in method greet
// Çıxış: Hello, Alice

// 2. Dekorator Fabriki
function validateParameter(required: boolean) {
  return function (target: any, propertyKey: string, parameterIndex: number) {
    const metadataKey = `__validate_${propertyKey}_${parameterIndex}`;
    target[metadataKey] = required;
  };
}
class UserService {
  addUser(@validateParameter(true) name: string, age: number): string {
    if (!name) throw new Error("Name is required");
    return `User ${name} with age ${age} added`;
  }
}
const userService = new UserService();
console.log(userService.addUser("Bob", 30)); // Çıxış: User Bob with age 30 added
// console.log(userService.addUser("", 30)); // Səhv: Name is required

// 3. Metod Dekoratoru ilə Birləşmə
function validateMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    args.forEach((arg, index) => {
      const metadataKey = `__validate_${propertyKey}_${index}`;
      if (target[metadataKey] && !arg) {
        throw new Error(`Parameter ${index} in ${propertyKey} is required`);
      }
    });
    return originalMethod.apply(this, args);
  };
}
class Profile {
  @validateMethod
  updateProfile(@validateParameter(true) name: string, @validateParameter(false) bio: string): string {
    return `Profile updated with name ${name} and bio ${bio || "N/A"}`;
  }
}
const profile = new Profile();
console.log(profile.updateProfile("Alice", "Developer")); // Çıxış: Profile updated with name Alice and bio Developer
// console.log(profile.updateProfile("", "Developer")); // Səhv: Parameter 0 in updateProfile is required

// 4. Sinif Dekoratoru ilə Birləşmə
function logClass(prefix: string) {
  return function (constructor: Function) {
    console.log(prefix + " class created: " + constructor.name);
  };
}
@logClass("INFO")
class Store {
  @validateMethod
  addProduct(@validateParameter(true) id: string, name: string): string {
    return `Product ${id}: ${name} added`;
  }
}
const store = new Store();
console.log(store.addProduct("P001", "Laptop")); // Çıxış: INFO class created: Store
// Çıxış: Product P001: Laptop added
// console.log(store.addProduct("", "Laptop")); // Səhv: Parameter 0 in addProduct is required

// Mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

function validateId(target: any, propertyKey: string, parameterIndex: number) {
  const metadataKey = `__validate_${propertyKey}_${parameterIndex}`;
  target[metadataKey] = true;
}

function validateMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    args.forEach((arg, index) => {
      const metadataKey = `__validate_${propertyKey}_${index}`;
      if (target[metadataKey] && !arg) {
        throw new Error(`Parameter ${index} in ${propertyKey} is required`);
      }
    });
    return originalMethod.apply(this, args);
  };
}

class Store {
  products: Product[] = [];

  @validateMethod
  addProduct(@validateId id: string, name: string, price: number): Product[] {
    const product: Product = { id, name, price };
    this.products = [...this.products, product];
    return this.products;
  }
}

const store = new Store();
console.log(store.addProduct("P001", "Laptop", 999)); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]
// console.log(store.addProduct("", "Laptop", 999)); // Səhv: Parameter 0 in addProduct is required

